#pragma OPENCL EXTENSION cl_khr_fp64 : enable
__constant double PI = 3.1415926535897932;
__constant long M = 2147483647;
__constant int A = 1103515245;
__constant int C = 12345;

double randu(__global int *seed, int index) {
    int num = A * seed[index] + C;
    seed[index] = num % M;
    return fabs((double)seed[index] / (double)M);
}

double randn(__global int *seed, int index) {
    double u = randu(seed, index);
    double v = randu(seed, index);
    double cosine = cos(2.0 * PI * v);
    double rt = -2.0 * log(u);
    return sqrt(rt) * cosine;
}

int roundDouble(double value) {
    int newValue = (int)value;
    if (value - newValue < 0.5)
        return newValue;
    else
        return newValue + 1;
}

__kernel void likelihood_kernel(__global double* arrayX,
                                __global double* arrayY,
                                __global double* xj,
                                __global double* yj,
                                __global double* CDF,
                                __global int* ind,
                                __global int* objxy,
                                __global double* likelihood,
                                __global unsigned char* I,
                                __global double* u,
                                __global double* weights,
                                int Nparticles,
                                int countOnes,
                                int max_size,
                                int k,
                                int IszY,
                                int Nfr,
                                __global int* seed,
                                __global double* partial_sums,
                                __local double* local_sums)
{
    int gid = get_global_id(0);
    if (gid >= Nparticles) return;

    // Update positions with noise
    // Note: randn cannot be directly called here; simulate noise with seed?
    // For simplicity, leave noise outside or just update positions on host.

    // Prepare indices and likelihood
    double lik = 0.0;
    int indX, indY;
    for (int y = 0; y < countOnes; y++) {
        indX = roundDouble(arrayX[gid]) + objxy[y * 2 + 1];
        indY = roundDouble(arrayY[gid]) + objxy[y * 2];
        int index = abs(indX * IszY * Nfr + indY * Nfr + k);
        if (index >= max_size) index = 0;
        ind[gid * countOnes + y] = index;

        int val = (int)I[index];
        lik += ((val - 100) * (val - 100) - (val - 228) * (val - 228)) / 50.0;
    }
    likelihood[gid] = lik / (double)countOnes;

    // Compute weights * exp(likelihood)
    weights[gid] = weights[gid] * exp(likelihood[gid]);

    // Reduction to sum weights
    local_sums[get_local_id(0)] = weights[gid];
    barrier(CLK_LOCAL_MEM_FENCE);

    int local_size = get_local_size(0);
    for (int offset = local_size / 2; offset > 0; offset >>= 1) {
        if (get_local_id(0) < offset) {
            local_sums[get_local_id(0)] += local_sums[get_local_id(0) + offset];
        }
        barrier(CLK_LOCAL_MEM_FENCE);
    }

    if (get_local_id(0) == 0) {
        partial_sums[get_group_id(0)] = local_sums[0];
    }
}

__kernel void sum_kernel(__global double* partial_sums, int Nparticles) {
    int gid = get_global_id(0);
    if (gid != 0) return;
    double sum = 0.0;
    for (int i = 0; i < (Nparticles + 511) / 512; i++) {
        sum += partial_sums[i];
    }
    partial_sums[0] = sum;
}

__kernel void normalize_weights_kernel(__global double* weights,
                                       int Nparticles,
                                       __global double* partial_sums,
                                       __global double* CDF,
                                       __global double* u,
                                       __global int* seed)
{
    int gid = get_global_id(0);
    if (gid >= Nparticles) return;

    double sumWeights = partial_sums[0];
    weights[gid] = weights[gid] / sumWeights;

    // Calculate CDF
    // Simple prefix sum: Not efficient but for demonstration
    barrier(CLK_GLOBAL_MEM_FENCE);
    CDF[gid] = weights[gid];
    barrier(CLK_GLOBAL_MEM_FENCE);
    for (int offset = 1; offset < Nparticles; offset <<= 1) {
        if (gid >= offset)
            CDF[gid] += CDF[gid - offset];
        barrier(CLK_GLOBAL_MEM_FENCE);
    }

    // Calculate u array (resampling offsets)
    double u1 = u[0]; // u[0] is uniform random offset
    u[gid] = u1 + (double)gid / (double)Nparticles;
}

int findIndex(__global double* CDF, int lengthCDF, double value) {
    int index = -1;
    for (int x = 0; x < lengthCDF; x++) {
        if (CDF[x] >= value) {
            index = x;
            break;
        }
    }
    if (index == -1) {
        return lengthCDF - 1;
    }
    return index;
}

__kernel void find_index_kernel(__global double* arrayX,
                               __global double* arrayY,
                               __global double* CDF,
                               __global double* u,
                               __global double* xj,
                               __global double* yj,
                               __global double* weights,
                               int Nparticles)
{
    int gid = get_global_id(0);
    if (gid >= Nparticles) return;

    int i = -1;
    double val = u[gid];
    for (int x = 0; x < Nparticles; x++) {
        if (CDF[x] >= val) {
            i = x;
            break;
        }
    }
    if (i == -1) i = Nparticles - 1;

    xj[gid] = arrayX[i];
    yj[gid] = arrayY[i];

    // Reset weight
    weights[gid] = 1.0 / (double)Nparticles;
}

