#pragma OPENCL EXTENSION cl_khr_fp64 : enable

__constant double PI = 3.1415926535897932;

__kernel void update_positions_kernel(__global double* arrayX,
                                      __global double* arrayY,
                                      __global int* seed,
                                      int Nparticles)
{
    int gid = get_global_id(0);
    if (gid >= Nparticles) return;

    // Note: randn() cannot be implemented as is on device without RNG state.
    // For demonstration, we use a simple linear congruential generator for noise.

    int s = seed[gid];
    s = (1103515245 * s + 12345) & 0x7fffffff;
    seed[gid] = s;

    double noiseX = 1.0 + 5.0 * (fabs((double)s / 2147483647.0) - 0.5);
    s = (1103515245 * s + 12345) & 0x7fffffff;
    seed[gid] = s;
    double noiseY = -2.0 + 2.0 * (fabs((double)s / 2147483647.0) - 0.5);

    arrayX[gid] += noiseX;
    arrayY[gid] += noiseY;
}

__kernel void copy_arrays_kernel(__global double* srcX,
                                 __global double* srcY,
                                 __global double* dstX,
                                 __global double* dstY,
                                 int Nparticles)
{
    int gid = get_global_id(0);
    if (gid >= Nparticles) return;

    dstX[gid] = srcX[gid];
    dstY[gid] = srcY[gid];
}

__kernel void reset_weights_kernel(__global double* weights,
                                   int Nparticles)
{
    int gid = get_global_id(0);
    if (gid >= Nparticles) return;

    weights[gid] = 1.0 / (double)Nparticles;
}

