#pragma OPENCL EXTENSION cl_khr_fp64 : enable

__kernel void dilate_disk_kernel(__global unsigned char* matrix,
                                 int posX,
                                 int posY,
                                 int posZ,
                                 int dimX,
                                 int dimY,
                                 int dimZ,
                                 int error)
{
    int x = get_global_id(0);
    int y = get_global_id(1);
    if (x >= dimX || y >= dimY) return;

    int startX = posX - error;
    if (startX < 0) startX = 0;
    int startY = posY - error;
    if (startY < 0) startY = 0;
    int endX = posX + error;
    if (endX > dimX) endX = dimX;
    int endY = posY + error;
    if (endY > dimY) endY = dimY;

    // Check distance and set if in radius
    double distance = sqrt((double)((x - posX)*(x - posX) + (y - posY)*(y - posY)));
    if (distance < error) {
        int idx = x * dimY * dimZ + y * dimZ + posZ;
        matrix[idx] = 1;
    }
}

__kernel void imdilate_disk_kernel(__global unsigned char* matrix,
                                   int dimX,
                                   int dimY,
                                   int dimZ,
                                   int error,
                                   __global unsigned char* newMatrix)
{
    int z = get_global_id(0);
    int x = get_global_id(1);
    int y = get_global_id(2);

    if (z >= dimZ || x >= dimX || y >= dimY) return;

    int idx = x * dimY * dimZ + y * dimZ + z;
    if (matrix[idx] == 1) {
        int startX = x - error;
        if (startX < 0) startX = 0;
        int startY = y - error;
        if (startY < 0) startY = 0;
        int endX = x + error;
        if (endX > dimX) endX = dimX;
        int endY = y + error;
        if (endY > dimY) endY = dimY;

        for (int i = startX; i < endX; i++) {
            for (int j = startY; j < endY; j++) {
                double dist = sqrt((double)((i - x)*(i - x) + (j - y)*(j - y)));
                if (dist < error) {
                    int newIdx = i * dimY * dimZ + j * dimZ + z;
                    newMatrix[newIdx] = 1;
                }
            }
        }
    }
}
